package jetbrains.mps.baseLanguage.unitTest.execution.tool;

/*Generated by MPS */

import jetbrains.mps.baseLanguage.unitTest.execution.TestNodeKey;
import org.jetbrains.annotations.NotNull;
import jetbrains.mps.util.NameUtil;

public abstract class NonRootTestTreeNode extends TestTreeNode {
  private final TestNodeKey myTest;


  protected NonRootTestTreeNode(@NotNull TestNodeKey test) {
    myTest = test;
    // XXX why do we care about UO when there's getTestNode() we use anyway
    setUserObject(test);
    // we use nodeIdentifier of a tree element in BaseMPSTestProxy subclasses for #getLocationUrl(),
    // which seem to serve the only purpose to copy string representation of a test into clipboard
    setNodeIdentifier(test.getQualifiedName());
    // indeed, sort of hack (assuming method name uses '.' as delimiter (e.g. in TestMethodNodeKey), just don't want to add separate getName() ATM
    // just for this scenario, and I don't envision any other use for getName()
    setText(NameUtil.shortNameFromLongName(test.getQualifiedName()));
  }

  @NotNull
  public TestNodeKey testKey() {
    return myTest;
  }
}
